var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"말씀하셨던 대로 그 괴물이 쓰는 총기를 새로 생산했어요.","JPN":"言われたとおり、あの化け物の銃器と同じものを生産しました。","ENG":"As you instructed, we made a new copy of the gun that monster uses.","TWN":"我已經照你的吩咐，重新生產那個怪物使用的槍枝。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"그런데 고모, 감찰과로 그 괴물을 쫓아낸 건 그렇다쳐도…….","JPN":"それにしても、叔母さん。あの化け物を監察課に追いやったところまでは良いとして……","ENG":"I get why you made Investigations track that monster down...","TWN":"不過姑姑，就算你想藉由監察科之手趕走那個怪物……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"굳이 삼촌까지 죽여야 했어요?","JPN":"叔父さんまで殺す必要はなかったのでは？","ENG":"But did you have to kill Uncle?","TWN":"也犯不著要叔叔的命吧？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"안 그러면? 그 성질 더러운 오빠가 이사회에서 물러나란다고 곱게 물러날 것 같니?","JPN":"じゃあ、どうすればよかったの？　理事会から辞任を求められたところで、あの頑固な男が大人しく辞めると思う？","ENG":"And if I didn’t? Do you think that he would step down from power that easily?","TWN":"不然呢？你以為我那奸詐的哥哥會這麼聽董事會的話，叫他退就退嗎？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"그, 그럼요?","JPN":"な、何か企んでいたと？","ENG":"M-maybe?","TWN":"他會怎樣？"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"글쎄. 무슨 꿍꿍이를 품었을지는 나도 모르지.","JPN":"さあ、どういう心づもりだったかはわからないわ。","ENG":"I don’t think so. But who knows what that old man was scheming...","TWN":"我也不知道他在打什麼鬼主意。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"하지만 이사회가 오빠를 끌어냈든, 오빠가 이사회를 뒤통수를 쳤든…….","JPN":"でも、理事会が兄さんを引きずり下ろしたとしても、\\n逆に兄さんが理事会に不意打ちをしかけたとしても……","ENG":"But it doesn’t matter if he stepped down by vote, or he got back at the board...","TWN":"我只知道，無論是董事會把我哥弄走，或是我哥反咬董事會一口……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"우리 조카님이 고를 수 있는 건 자충수밖에 없었을걸.","JPN":"甥っ子の君には、自分の首を締める選択肢しか残されていなかったはずよ？","ENG":"I’m sure your choice of action wouldn’t have been that different anyway.","TWN":"要是沒有我的幫忙的話，"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"내가 힘써 주지 않았다면 말이야.","JPN":"私の協力が無ければね。","ENG":"If it weren’t for my help, hmm, nephew?","TWN":"你的下場都會很慘！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"알아요, 다 안다고요. 그러니까 저도 회장이 되기 위해 고모랑 손잡은 거잖아요.","JPN":"わかってる、わかってます。だから俺も会長になるために、叔母さんと手を組んだんです。","ENG":"I know, I know. Isn’t that why I decided to join you, Auntie? So I could become President of Alphatrix?","TWN":"我知道，我知道，所以我才和姑姑一起合作要當上會長的嘛！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"저도 나름대로 이번 회장 선발전에 목숨을 걸고 있다고요!","JPN":"俺も自分なりに、今回の会長選出に命がけで臨んでいるんですよ！","ENG":"You know, I’m putting my life on the line, much like you!","TWN":"這次的會長選舉，我也是賭上性命的！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"우리 조카님이 큰 결심을 했구나. 원래 도박은 판돈이 커져야 제맛이긴 하지.","JPN":"それは大英断だと思うわ。賭博って、やっぱり賭けるものが増えれば増えるほど盛り上がるし。","ENG":"My little nephew appears to have made up his mind! But, as they say, \\"high risk, high reward.\\"","TWN":"看來你也是下定決心，不過在賭桌上，賭注不大本來就沒什麼意思。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"……그리고 목숨만 한 판돈도 없고 말이야.","JPN":"……賭けるなら、命以上のものも無いしね。","ENG":"Besides, nothing’s more thrilling than putting your own life on the line.","TWN":"……而且沒有比性命更大的賭注！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"그보다 아직 안 갔니? 슬슬 도착할 때가 다 됐는데?","JPN":"それより、まだ届いていないのかしら？　そろそろ着く頃だけど。","ENG":"By the way, why haven’t you left already? It should be arriving any time now.","TWN":"還沒到嗎？差不多該到了吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"네? 도착하다니 뭐가요?","JPN":"え？　着くって、何がですか？","ENG":"Huh? What’s about to arrive?","TWN":"嗯？什麼東西到了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"우리 조카님을 위한 <color=#ffd34c>특별 선물</color>.","JPN":"私の甥っ子のための<color=#ffd34c>特別プレゼント</color>よ。","ENG":"Just a little <color=#ffd34c>special present</color> I prepared for my precious nephew.","TWN":"是我專門為姪子準備的<color=#ffd34c>禮物</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"이 나이 먹고 선물은 무슨……. 헬기라도 한 대 주시게요?","JPN":"もうそんな年でもないのに……ヘリでもプレゼントしてくれるんですか？","ENG":"Aren’t I a bit too old to be receiving presents? What did you get me? A helicopter?","TWN":"我都長這麼大了，還送什麼禮物……難道是要送我一台直升機？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"뭐야? 이 시간에 누구야?!","JPN":"何だ、こんな時間に誰だ！？","ENG":"Huh?! Who’s knocking at this hour?!","TWN":"怎麼回事？這個時間會是誰？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"너, 너는……?","JPN":"お、お前は……！","ENG":"Y-you’re...?","TWN":"你……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};